    int hi = arr.length - 1; // Changed to arr.length - 1
    while (lo <= hi) {
        int mid = (lo + hi) / 2; 
        if (x == arr[mid] && (mid == 0 || x != arr[mid - 1])) {
            return mid;
        } else if (x < arr[mid]) { // Changed to x < arr[mid] for correct comparison
            hi = mid - 1; // Changed to mid - 1 to avoid infinite loop
        } else {
            lo = mid + 1;
        }
    }
    return -1;
}

